#include <stdio.h>
#define MOD 423734237342373
int main() {
    int N, S, T, K;
    scanf("%d", &N);
    int adj[N][N];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            scanf("%d", &adj[i][j]);
        }
    }
    scanf("%d %d %d", &S, &T, &K);
    long long dp[N][K + 1];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j <= K; j++) {
            dp[i][j] = 0;
        }
    }
    dp[S - 1][0] = 1;
    for (int i = 1; i <= K; i++) {
        for (int j = 0; j < N; j++) {
            for (int k = 0; k < N; k++) {
                if (adj[j][k] > 0) {
                    dp[k][i] = (dp[k][i] + dp[j][i - 1] * adj[j][k]) % MOD;
                }
            }
        }
    }
    printf("%lld\n", dp[T - 1][K]);
    return 0;
}

